class Solution {
    public int numWays(int steps, int arrLen) {
        final int MOD = (int) 1e9 + 7;
        arrLen = Math.min(arrLen, steps + 1);
        int[][] dp = new int[arrLen][steps + 1];
        dp[0][0] = 1;
        for (int j = 1; j <= steps; j++) {
            for (int i = 0; i < arrLen; i++) {
                dp[i][j] = dp[i][j - 1];
                if (i > 0) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % MOD;
                }
                if (i < arrLen - 1) {
                    dp[i][j] = (dp[i][j] + dp[i + 1][j - 1]) % MOD;
                }
            }
        }
        return dp[0][steps];
    }
}
